SKIPPED_MODULE = ['lora']


def skipped_module(name: str, patterns: list[str]):
    """Whether the module should be skipped from quantization.

    Args:
        name: The fully-qualified module name.
        patterns: The list of patterns for modules to skip.
    """

    patterns.extend(SKIPPED_MODULE)

    return next(((True, pattern) for pattern in patterns if pattern in name), (False, None))


@torch.no_grad()
def get_weight_scale(weight, q_group_size=-1):
    org_shape = weight.shape
    if q_group_size > 0:
        weight = weight.view(-1, q_group_size)
    abs_weight = weight.abs()
    abs_weight_amax = abs_weight.amax(dim=1, keepdim=True)
    if abs_weight_amax.min().item() == 0:
        print('weight.amax.min is zero, clamping weight.amax to 1e-4')
        abs_weight_amax = abs_weight_amax.clamp(min=1e-4)
    scale = abs_weight / abs_weight_amax
    scale = scale.view(org_shape)
    scale = scale.mean(0)
    return scale
